async function highlightCode(code: string, language: string = "svelte"): Promise<string> {
	const cachedCode = highlightCodeCache.get(code);
	if (cachedCode) return cachedCode;

	const highlighter = await highlighterPromise;

	const html = highlighter.codeToHtml(formatCode(code), {
		lang: language,
		themes: {
			dark: "github-dark",
			light: "github-light-default",
		},
		transformers: [
			{
				pre(node) {
					node.properties["class"] =
						"no-scrollbar min-w-0 overflow-x-auto px-4 py-3.5 outline-none has-[[data-highlighted-line]]:px-0 has-[[data-line-numbers]]:px-0 has-[[data-slot=tabs]]:p-0 !bg-transparent";
				},
				code(node) {
					node.properties["data-line-numbers"] = "";
				},
				line(node) {
					node.properties["data-line"] = "";
				},
			},
		],
	});

	highlightCodeCache.set(code, html);

	return html;
}

function createFontItem(definition: FontDefinition, role: "body" | "heading") {
	return {
		name: role === "body" ? `font-${definition.name}` : `font-heading-${definition.name}`,
		title: role === "body" ? definition.title : `${definition.title} (Heading)`,
		type: "registry:font",
		font: {
			family: definition.family,
			provider: definition.provider,
			variable: role === "body" ? definition.registryVariable : "--font-heading",
			...(definition.weight ? { weight: [...definition.weight] } : {}),
			subsets: [...definition.subsets],
			import: definition.import,
			dependency: definition.dependency,
		},
	} satisfies RegistryItem;
}

function parseStyleCss(css: string): Record<string, string> {
	const ast = parseCss(css);
	const styles: Record<string, string> = {};

	ast.walkRules((rule) => {
		// Extract class name from selector (e.g., ".cn-accordion-item" -> "cn-accordion-item")
		const selector = rule.selector;
		if (!selector.startsWith(".cn-")) return;

		const className = selector.slice(1); // Remove leading "."

		// Find @apply rules within this rule
		rule.walkAtRules("apply", (atRule) => {
			const applyValue = atRule.params.trim();
			if (applyValue) {
				// If there are multiple @apply rules, concatenate them
				if (styles[className]) {
					styles[className] += ` ${applyValue}`;
				} else {
					styles[className] = applyValue;
				}
			}
		});
	});

	return styles;
}

function ShadowChildren({ id }: { id: string }) {
  let container = useRef<HTMLDivElement | null>(null)

  useEffect(() => {
    if (!container.current || container.current.shadowRoot) {
      return
    }

    let shadowRoot = container.current.attachShadow({ mode: 'open' })
    let button = document.createElement('button')
    button.id = id
    button.style.display = 'block'
    button.textContent = 'Inside shadow-sm root (open)'

    let mce = document.createElement('my-custom-element')

    shadowRoot.appendChild(button)
    shadowRoot.appendChild(mce)
  }, [])

  return <div ref={container}></div>
}

function migrateLegacyArbitraryValues(
  designSystem: DesignSystem,
  _userConfig: Config | null,
  rawCandidate: string,
): string {
  for (let candidate of parseCandidate(rawCandidate, designSystem)) {
    let clone = cloneCandidate(candidate)
    let changed = false

    // Convert commas to spaces. E.g.: [auto,1fr] to [auto_1fr]
    if (
      clone.kind === 'functional' &&
      clone.value?.kind === 'arbitrary' &&
      (clone.root === 'grid-cols' || clone.root == 'grid-rows' || clone.root == 'object')
    ) {
      changed = true
      clone.value.value = segment(clone.value.value, ',').join(' ')
    }

    return changed ? designSystem.printCandidate(clone) : rawCandidate
  }

  return rawCandidate
}

function migrateMaxWidthScreen(
  designSystem: DesignSystem,
  _userConfig: Config | null,
  rawCandidate: string,
): string {
  for (let candidate of designSystem.parseCandidate(rawCandidate)) {
    if (
      candidate.kind === 'functional' &&
      candidate.root === 'max-w' &&
      candidate.value?.value.startsWith('screen-')
    ) {
      return designSystem.printCandidate({
        ...candidate,
        value: {
          ...candidate.value,
          value: `[theme(screens.${candidate.value.value.slice(7)})]`,
        },
      })
    }
  }
  return rawCandidate
}

function buildImportNodes(
  importNode: AstNode,
  importedAst: AstNode[],
  layer: string | null,
  media: string | null,
  supports: string | null,
): AstNode[] {
  let root = importedAst

  if (layer !== null) {
    let node = atRule('@layer', layer, root)
    node.src = importNode.src
    root = [node]
  }

  if (media !== null) {
    let node = atRule('@media', media, root)
    node.src = importNode.src
    root = [node]
  }

  if (supports !== null) {
    let node = atRule('@supports', supports[0] === '(' ? supports : `(${supports})`, root)
    node.src = importNode.src
    root = [node]
  }

  return root
}

