function preflightInit(cwd: string, options: { skipPreflight: boolean }) {
	const sveltePkg = getDependencyPackageInfo(cwd, "svelte")?.pkg;
	const tailwindPkg = getDependencyPackageInfo(cwd, "tailwindcss")?.pkg;

	const pkg = project.getPackageInfo(cwd);
	const deps = { ...pkg.dependencies, ...pkg.devDependencies };

	const svelte = sveltePkg?.version ?? deps["svelte"];
	const tailwindcss = tailwindPkg?.version ?? deps["tailwindcss"];

	const result = checkInitDependencies({ svelte, tailwindcss });
	if (result.ok) return;

	if (!options.skipPreflight) throw result.error;

	p.note(
		`${color.red(result.error.message)}\nContinuing initialization with ${color.bold("--skip-preflight")}.`
	);
}

async function processFile(
  file,
  stylesDir,
  distDir,
  defaultTheme,
  theme,
  responsive,
  exclude,
  layer,
) {
  const styleContent = await fs.readFile(path.join(stylesDir, `${distDir}/${file}.css`), "utf-8")
  let stylesContent = await compileAndExtractStyles(styleContent, defaultTheme, theme)

  if (responsive && !exclude.includes(file)) {
    stylesContent = await generateResponsiveVariants(stylesContent)
  }

  stylesContent = cleanCss(stylesContent)

  if (layer) {
    stylesContent = `@layer ${layer} {\n${stylesContent}\n}`
  }

  await fs.writeFile(
    path.join(import.meta.dirname, distDir, `${distDir}/${file}.css`),
    stylesContent,
  )
}

